using System.Collections.Generic;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Mvc;
using PagamentoApi.Models;
using PagamentoApi.Models.Partial;
using PagamentoApi.Repositories;
using System;

namespace PagamentoApi.Controllers
{
    [ApiController]
    [Route("v1/[controller]")]
    public class UsuarioController : ControllerBase
    {

        [HttpGet]
        [Authorize(Roles = "usuario")]
        public async Task<dynamic> Get([FromServices] ClientelaRepository clientelaRepository)
        {
            List<ClientelaApp> usuarios = new List<ClientelaApp>();
            if (User.Identity.Name == "99999999999")
            {
                var foto = "";
                var usuario = new ClientelaApp
                {
                    NMCLIENTE = "SESQUITO TOCANTINS",
                    Matricula = "9999-999999-9",
                    Categoria = "TRABALHADOR DO COMÉRCIO",
                    Cdbarras = "99999999999",
                    NUCPF = "99999999999",
                    FOTO = Convert.FromBase64String(foto),
                    DTNASCIMEN = Convert.ToDateTime("01/01/2018"),
                    DTVENCTO = Convert.ToDateTime("01/01/2024"),
                    NUMCARTAO = 96
                };
                usuarios.Add(usuario);
            }
            else
            {
                usuarios = await clientelaRepository.ObterClientePorCpfSemCobrancas(User.Identity.Name);
            }
            //List<ClientelaApp> usuarios = await clientelaRepository.ObterClientePorCpfSemCobrancas(User.Identity.Name);
            return usuarios;
        }

        [HttpGet]
        [Route("cobrancas/{cpf}/{ano}")]
        [Authorize(Roles = "app")]
        public List<COBRANCA> GetCobrancas([FromServices] UsuarioCliente usuarioCliente, [FromServices] CobrancaRepository cobrancaRepository, string cpf, int ano)
        {
            var usuario = usuarioCliente.getUsuario(cpf);
            var cobrancas = cobrancaRepository.getCobrancas(usuario, ano);
            return cobrancas;

        }

        [HttpGet]
        [Route("cliente/{cpf}")]
        [Authorize(Roles = "app")]
        public async Task<CLIENTELA> GetClientePorCpf([FromServices] ClientelaRepository clientelaRepository, string cpf)
        {
            var cliente = await clientelaRepository.getClientePorCpf(cpf);
            return cliente;
        }

        [HttpGet]
        [Route("caixa/{pessoa}")]
        [Authorize(Roles = "app")]
        public CACAIXA GetCaixaPorPessoa([FromServices] CaixaRepository caixaRepository, string pessoa)
        {
            var caixa = caixaRepository.GetCaixaPorUsuario(pessoa);
            return caixa;

        }

        [HttpGet]
        [Route("doisFatores/{cpf}")]
        [Authorize(Roles = "usuario")]
        public async Task<bool> GetDoisFatoresHabilitado([FromServices] ClientelaRepository clientelaRepository, string cpf)
        {
            return await clientelaRepository.GetDoisFatoresHabilitado(cpf);
        }

        [HttpPost]
        [Route("doisFatores/atualiza/{cpf}/{valorDoisFatores}")]
        [Authorize(Roles = "usuario")]
        public async Task<bool> AtualizaDoisFatores([FromServices] ClientelaRepository clientelaRepository, string cpf, bool valorDoisFatores)
        {
            return await clientelaRepository.AtualizaDoisFatores(cpf, valorDoisFatores);
        }
    }
}